INSERT INTO supplemental_essays (id, college_id, prompt, word_limit) VALUES (gen_random_uuid(), (SELECT id FROM colleges WHERE full_name = 'University of Texas at Austin'), 'Why are you interested in the major you indicated as your first-choice major?  Please limit your response to 250-300 words.', 300);
INSERT INTO supplemental_essays (id, college_id, prompt, word_limit) VALUES (gen_random_uuid(), (SELECT id FROM colleges WHERE full_name = 'University of Texas at Austin'), 'Describe how your experiences, perspectives, talents, and/or your involvement in leadership activities (at your school, job, community, or within your family) will help you to make an impact both in and out of the classroom while enrolled at UT.  Please limit your response to 250-300 words.', 300);
INSERT INTO supplemental_essays (id, college_id, prompt, word_limit) VALUES (gen_random_uuid(), (SELECT id FROM colleges WHERE full_name = 'University of Texas at Austin'), 'The core purpose of The University of Texas at Austin is, To Transform Lives for the Benefit of Society. Please share how you believe your experience at UT-Austin will prepare you to Change the World after you graduate.  Please limit your response to 250-300 words.', 300);
INSERT INTO supplemental_essays (id, college_id, prompt, word_limit) VALUES (gen_random_uuid(), (SELECT id FROM colleges WHERE full_name = 'University of Texas at Austin'), 'Please share background on events or special circumstances that you feel may have impacted your high school academic performance.  If your response to this question is similar to one of the Common App Personal Essays, feel free to simply copy and paste the important parts of your essay here.   Please limit your response to 250-300 words.', 300);
INSERT INTO supplemental_essays (id, college_id, prompt, word_limit) VALUES (gen_random_uuid(), (SELECT id FROM colleges WHERE full_name = 'University of Texas at Austin'), 'Tell us your story. What unique opportunities or challenges have you experienced throughout your high school career that have shaped who you are today?  Please keep your essay between 500–700 words (typically two to three paragraphs).', 700);
